import time
import ubinascii
import machine
import network
from umqtt.simple import MQTTClient

WIFI_SSID = "YOUR_WIFI_SSID"
WIFI_PASSWORD = "YOUR_WIFI_PASSWORD"

BROKER_IP = "192.168.1.10"
TOPIC_TEMP = b"sensors/temp"

PUBLISH_INTERVAL_S = 5


def wifi_connect(ssid, password, timeout_s=20):
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    if not wlan.isconnected():
        wlan.connect(ssid, password)
        start = time.ticks_ms()
        while not wlan.isconnected():
            if time.ticks_diff(time.ticks_ms(), start) > timeout_s * 1000:
                raise OSError("WiFi connect timeout")
            time.sleep_ms(200)
    return wlan


def read_temperature_c():
    try:
        return float((machine.temperature() - 32.0) * (5.0 / 9.0))
    except:
        return 25.0


def make_client():
    client_id = b"esp32-" + ubinascii.hexlify(machine.unique_id())
    return MQTTClient(client_id, BROKER_IP)


def main():
    wifi_connect(WIFI_SSID, WIFI_PASSWORD)

    client = make_client()
    client.connect()

    while True:
        try:
            temp_c = read_temperature_c()
            payload = ("%.2f" % temp_c).encode()
            client.publish(TOPIC_TEMP, payload)
            time.sleep(PUBLISH_INTERVAL_S)
        except OSError:
            try:
                client.disconnect()
            except:
                pass
            time.sleep(2)
            try:
                wifi_connect(WIFI_SSID, WIFI_PASSWORD)
            except:
                pass
            client = make_client()
            try:
                client.connect()
            except:
                time.sleep(2)


if __name__ == "__main__":
    main()